import json
# Load children books results
def load_if_path(val):
    if isinstance(val, str) and val.endswith('.json'):
        with open(val, 'r') as f:
            return json.load(f)
    else:
        return val

children_raw = locals()['var_functions.query_db:5']
children_books = load_if_path(children_raw)
rating_raw = locals()['var_functions.query_db:22']
rating_books = load_if_path(rating_raw)
# Extract numeric part from children book ids
children_nums = {}
for rec in children_books:
    try:
        # rec['book_id'] looks like 'bookid_4'
        num = int(rec['book_id'].split('_')[1])
        children_nums[num] = rec
    except Exception as e:
        continue
# Build set of book numbers meeting rating threshold
rating_nums = {int(r['book_num']): float(r['avg_rating']) for r in rating_books}
# Filter those in both
matched = []
for num, child_rec in children_nums.items():
    if num in rating_nums:
        matched.append({
            'book_id': child_rec['book_id'],
            'title': child_rec['title'],
            'avg_rating': rating_nums[num],
        })
# Sort by avg_rating descending
matched = sorted(matched, key=lambda x: x['avg_rating'], reverse=True)
print('__RESULT__:')
print(json.dumps(matched, ensure_ascii=False))

